import{_ as r,o as t,c as p,j as e,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"天心","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/天心.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/天心.md"}'),o={name:"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/天心.md"};function d(l,a,i,_,c,h){return t(),p("div",null,[...a[0]||(a[0]=[e("h1",{id:"天心",tabindex:"-1"},[n("天心 "),e("a",{class:"header-anchor",href:"#天心","aria-label":'Permalink to "天心"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"灵魂蓝调019")])])],-1),s('<h1 id="天心-1" tabindex="-1">天心 <a class="header-anchor" href="#天心-1" aria-label="Permalink to &quot;天心&quot;">​</a></h1><p>天心<br> D+1000<br> 自然本质<br> 周身由秘银铸成，剑锷处点缀着精致的青玛瑙和月亮石，柄上被一层深蓝色的皮革所包裹，轻柔而又锐利。</p><p>天心是一把完美的平衡的闪亮的秘银细剑，6L，破甲2，体积3，力量需求1。由于是用秘银打造而成，因此天心剑拥有【秘银】材质。</p><p>【秘银】：拥有秘银材质的武器在使用时视为具有【法破】，在格挡时还会提供1点幸运加值。</p><p>使用要求：剑3+，专注3+</p><p>不详征兆：每当天心剑被拔出时，时间仿佛变得缓慢，一秒钟会悄悄地溜走，你可以在这短暂的停滞中提升你的注意力。在你拔出剑的当回合，你的基础防御受到2点速度减值，专注检定获得2点洞察加值。</p><p>专属剑技-梦魇剑·青玉 D+500</p><p>描述：你仔细地阅读对手的防御动作，抓准时间攻击他防御中的空隙，即使是最强的防御在你敏锐的精神面前也是用空隙可钻的。</p><p>效果：使用标准动作发动这个技艺，你专注于目标防御的空隙，进行一次DC3的意志检定，如果检定成功，你将找出对方架势的破绽，这次近战攻击将获得3点技艺加值并附带C级措手不及；如果检定失败，此次攻击受到2点技艺减值。<br> 当你专注提升到8时，意味着你已经彻底熟练掌握了该剑技，检定默认成功。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const m=r(o,[["render",d]]);export{f as __pageData,m as default};
